はじめに
// サーバー側（Hono）
app.get('/posts/:id', (c) =&gt; {
  const post = findPost(c.req.param('id'))
  return c.render('Posts/Show', { post })
})
// クライアント側（React）
export default function Show({ post }: PageProps&lt;'Posts/Show'&gt;) {
  return &lt;h1&gt;{post.title}&lt;/h1&gt;
}
